function setTokenEnabled(address token, bool enabled) external onlyOwner {
    enabledTokens[token] = enabled;

    // enable native yields if token is recognized
    // no matter if it's enabled or not
    if (registry.nativeYieldTokens(token)) {
        BlastYields.enableTokenClaimable(token);
    }

    emit LogTokenDepositEnabled(token, enabled);
}

require(
    from != address(this) || token_ == USE_ETHEREUM || amount <= _tokenBalanceOf(token).sub(total.elastic),
    "BentoBox: Skim too much"
);

modifier allowed(address from) {
    if (from != msg.sender && from != address(this)) {
        address masterContract = masterContractOf[msg.sender];
        require(masterContract != address(0), "BentoBox: no masterContract");
        require(masterContractApproved[masterContract][from], "BentoBox: Transfer not approved");
    }
    _;
}
